        options: { a: 'Both Statement-I and Statement-II are correct and Statement-II is the correct explanation for Statement-I.', b: 'Both Statement-I and Statement-II are correct but Statement-II is not the correct explanation for Statement-I.', c: 'Statement-I is correct but Statement-II is incorrect.', d: 'Statement-I is incorrect but Statement-II is correct.' },
